var v=Object.create;var u=Object.defineProperty,f=Object.defineProperties,g=Object.getOwnPropertyDescriptor,h=Object.getOwnPropertyDescriptors,q=Object.getOwnPropertyNames,o=Object.getOwnPropertySymbols,x=Object.getPrototypeOf,d=Object.prototype.hasOwnProperty,p=Object.prototype.propertyIsEnumerable;var c=(e,s,t)=>s in e?u(e,s,{enumerable:!0,configurable:!0,writable:!0,value:t}):e[s]=t,L=(e,s)=>{for(var t in s||={})d.call(s,t)&&c(e,t,s[t]);if(o)for(var t of o(s))p.call(s,t)&&c(e,t,s[t]);return e},C=(e,s)=>f(e,h(s));var P=(e,s)=>{var t={};for(var i in e)d.call(e,i)&&s.indexOf(i)<0&&(t[i]=e[i]);if(e!=null&&o)for(var i of o(e))s.indexOf(i)<0&&p.call(e,i)&&(t[i]=e[i]);return t};var y=(e,s)=>()=>{try{return s||e((s={exports:{}}).exports,s),s.exports}catch(t){throw s=0,t}};var w=(e,s,t,i)=>{if(s&&typeof s=="object"||typeof s=="function")for(let n of q(s))!d.call(e,n)&&n!==t&&u(e,n,{get:()=>s[n],enumerable:!(i=g(s,n))||i.enumerable});return e};var A=(e,s,t)=>(t=e!=null?v(x(e)):{},w(s||!e||!e.__esModule?u(t,"default",{value:e,enumerable:!0}):t,e));var k=(e,s,t)=>new Promise((i,n)=>{var m=r=>{try{a(t.next(r))}catch(l){n(l)}},b=r=>{try{a(t.throw(r))}catch(l){n(l)}},a=r=>r.done?i(r.value):Promise.resolve(r.value).then(m,b);a((t=t.apply(e,s)).next())});var D=(()=>{class e{static{this.inMaintenance=!1}static{this.data={settings:{layout_type:"ltr",layout_version:"light"},app_name:"EMAC",keywords:"emac,ecole militaire des aspirants de coetquidant"}}static{this.wordings={settings:{dark:"Sombre",light:"Clair",rtl:"Dag",ltr:"Gad"},general:{goHome:"Retour \xE0 l'accueil",home:"Accueil",about:"\xC0 propos",blog:"Blog",gallery:"Galerie",social:"R\xE9seaux sociaux",back:"Retour",learn_more:"Plus d'information",close:"Fermer",sitemap:"Sitemap",search:"Rechercher",of:"De",contribute:"Contribuer"},privacy_policy:{title:"Politique de confidentialit\xE9",description:`<p>L'<strong>EMAC</strong>, soucieuse des droits des individus, notamment au regard des traitements automatis\xE9s et dans une volont\xE9 de transparence avec ses clients, a mis en place une politique reprenant l\u2019ensemble de ces traitements, des finalit\xE9s poursuivies par ces derniers ainsi que des moyens d\u2019actions \xE0 la disposition des individus afin qu\u2019ils puissent au mieux exercer leurs droits. <br>Pour toute information compl\xE9mentaire sur la protection des donn\xE9es personnelles, nous vous invitons \xE0 consulter le site : <a href="https://www.cnil.fr/">https://www.cnil.fr/</a><br><br>La poursuite de la navigation sur ce site vaut acceptation sans r\xE9serve des dispositions et conditions d'utilisation qui suivent.&nbsp;<br>La version actuellement en ligne de ces conditions d'utilisation est la seule opposable pendant toute la dur\xE9e d'utilisation du site et jusqu'\xE0 ce qu'une nouvelle version la remplace.<br><br></p><h5>Article 1 - Mentions l\xE9gales</h5><p><strong>1.1 Site (ci-apr\xE8s \xAB le site \xBB) :</strong></p><p><strong>EMAC </strong>- <a href="https:lucianobdt.org///">lucianobdt.org</a><br><br></p><p><strong>1.2 \xC9diteur (ci-apr\xE8s \xAB l'\xE9diteur \xBB) :</strong>&nbsp;</p><ul><li>L'<strong>EMAC </strong></li><li>Situ\xE9e : Acad\xE9mie militaire de Saint-Cyr Co\xEBtquidan, 56381 GUER Cedex, France</li><li>Adresse mail : <strong>emac.amscc@gmail.com</strong></li></ul><p><br></p><p><strong>1.3 H\xE9bergeur (ci-apr\xE8s \xAB l'h\xE9bergeur \xBB) :</strong></p><p><strong>EMAC</strong> - <a href="https://lucianobdt.org">lucianobdt.org</a> est h\xE9berg\xE9 par GitHub, dont le si\xE8ge social est situ\xE9 : 37 quai du pr\xE9sident Roosevelt, 92130 Issy-les-Moulineaux.<br><br></p><h5>Article 2 - Acc\xE8s au site</h5><p>L'acc\xE8s au site et son utilisation sont r\xE9serv\xE9s \xE0 un usage strictement personnel. Vous vous engagez \xE0 ne pas utiliser ce site et les informations ou donn\xE9es qui y figurent \xE0 des fins commerciales, politiques, publicitaires et pour toute forme de sollicitation commerciale et notamment l'envoi de courriers \xE9lectroniques non sollicit\xE9s.<br><br></p><h5>Article 3 - Contenu du site</h5><p>Toutes les marques, photographies, textes, commentaires, illustrations, images anim\xE9es ou non, s\xE9quences vid\xE9o, sons, ainsi que toutes les applications informatiques qui pourraient \xEAtre utilis\xE9es pour faire fonctionner ce site et plus g\xE9n\xE9ralement tous les \xE9l\xE9ments reproduits ou utilis\xE9s sur le site sont prot\xE9g\xE9s par les lois en vigueur au titre de la propri\xE9t\xE9 intellectuelle.<br>Ils sont la propri\xE9t\xE9 pleine et enti\xE8re de l'\xE9diteur ou de ses partenaires. Toute reproduction, repr\xE9sentation, utilisation ou adaptation, sous quelque forme que ce soit, de tout ou partie de ces \xE9l\xE9ments, y compris les applications informatiques, sans l'accord pr\xE9alable et \xE9crit de l'\xE9diteur, sont strictement interdites. Le fait pour l'\xE9diteur de ne pas engager de proc\xE9dure d\xE8s la prise de connaissance de ces utilisations non autoris\xE9es ne vaut pas acceptation desdites utilisations et renonciation aux poursuites.<br><br></p><h5>Article 4 - Gestion du site</h5><p>Pour la bonne gestion du site, l'\xE9diteur pourra \xE0 tout moment :</p><ul><li>suspendre, interrompre ou limiter l'acc\xE8s \xE0 tout ou partie du site, r\xE9server l'acc\xE8s au site, ou \xE0 certaines parties du site, \xE0 une cat\xE9gorie d\xE9termin\xE9e d'internautes ;</li><li>supprimer toute information pouvant en perturber le fonctionnement ou entrant en contravention avec les lois nationales ou internationales ;</li><li>suspendre le site afin de proc\xE9der \xE0 des mises \xE0 jour.</li></ul><p><br></p><h5>Article 5 - Responsabilit\xE9s</h5><p>La responsabilit\xE9 de l'\xE9diteur ne peut \xEAtre engag\xE9e en cas de d\xE9faillance, panne, difficult\xE9 ou interruption de fonctionnement, emp\xEAchant l'acc\xE8s au site ou \xE0 une de ses fonctionnalit\xE9s.<br>Le mat\xE9riel de connexion au site que vous utilisez est sous votre enti\xE8re responsabilit\xE9. Vous devez prendre toutes les mesures appropri\xE9es pour prot\xE9ger votre mat\xE9riel et vos propres donn\xE9es notamment d'attaques virales par Internet. Vous \xEAtes par ailleurs seul responsable des sites et donn\xE9es que vous consultez.<br><br>L'\xE9diteur ne pourra \xEAtre tenu responsable en cas de poursuites judiciaires \xE0 votre encontre :</p><ul><li>du fait de l'usage du site ou de tout service accessible via Internet ;</li><li>du fait du non-respect par vous des pr\xE9sentes conditions g\xE9n\xE9rales.</li></ul><p><br></p><p>L'\xE9diteur n'est pas responsable des dommages caus\xE9s \xE0 vous-m\xEAme, \xE0 des tiers et/ou \xE0 votre \xE9quipement du fait de votre connexion ou de votre utilisation du site et vous renoncez \xE0 toute action contre lui de ce fait.<br>Si l'\xE9diteur venait \xE0 faire l'objet d'une proc\xE9dure amiable ou judiciaire en raison de votre utilisation du site, il pourra se retourner contre vous pour obtenir l'indemnisation de tous les pr\xE9judices, sommes, condamnations et frais qui pourraient d\xE9couler de cette proc\xE9dure.<br><br></p><h5>Article 6 - Liens hypertextes</h5><p>La mise en place par les utilisateurs de tous liens hypertextes vers tout ou partie du site est autoris\xE9e par l'\xE9diteur. Tout lien devra \xEAtre retir\xE9 sur simple demande de l'\xE9diteur.&nbsp;<br>Toute information accessible via un lien vers d'autres sites n'est pas publi\xE9e par l'\xE9diteur. L'\xE9diteur ne dispose d'aucun droit sur le contenu pr\xE9sent dans ledit lien.<br><br></p><h5>Article 7 - Collecte et protection des donn\xE9es</h5><p>Vos donn\xE9es sont collect\xE9es par l'<strong>EMAC</strong>.<br>Une donn\xE9e \xE0 caract\xE8re personnel d\xE9signe toute information concernant une personne physique identifi\xE9e ou identifiable (personne concern\xE9e) ; est r\xE9put\xE9e identifiable une personne qui peut \xEAtre identifi\xE9e, directement ou indirectement, notamment par r\xE9f\xE9rence \xE0 un nom, un num\xE9ro d'identification ou \xE0 un ou plusieurs \xE9l\xE9ments sp\xE9cifiques, propres \xE0 son identit\xE9 physique, physiologique, g\xE9n\xE9tique, psychique, \xE9conomique, culturelle ou sociale.<br>Les informations personnelles pouvant \xEAtre recueillies sur le site sont principalement utilis\xE9es par l'\xE9diteur pour la gestion des relations avec vous, et le cas \xE9ch\xE9ant pour le traitement de vos commandes.&nbsp;<br><br>Les donn\xE9es personnelles collect\xE9es sont les suivantes :</p><ul><li>n\xE9ant</li></ul><p><br></p><h5>Article 8 - Droit d\u2019acc\xE8s, de rectification et de d\xE9r\xE9f\xE9rencement de vos donn\xE9es</h5><p>En application de la r\xE9glementation applicable aux donn\xE9es \xE0 caract\xE8re personnel, les utilisateurs disposent des droits suivants :</p><ul><li>le droit d\u2019acc\xE8s : ils peuvent exercer leur droit d'acc\xE8s, pour conna\xEEtre les donn\xE9es personnelles les concernant, en \xE9crivant \xE0 l'adresse \xE9lectronique ci-dessous mentionn\xE9e. Dans ce cas, avant la mise en \u0153uvre de ce droit, la Plateforme peut demander une preuve de l'identit\xE9 de l'utilisateur afin d'en v\xE9rifier l'exactitude ;</li><li>le droit de rectification : si les donn\xE9es \xE0 caract\xE8re personnel d\xE9tenues par la Plateforme sont inexactes, ils peuvent demander la mise \xE0 jour des informations ;</li><li>le droit de suppression des donn\xE9es : les utilisateurs peuvent demander la suppression de leurs donn\xE9es \xE0 caract\xE8re personnel, conform\xE9ment aux lois applicables en mati\xE8re de protection des donn\xE9es ;</li><li>le droit \xE0 la limitation du traitement : les utilisateurs peuvent de demander \xE0 la Plateforme de limiter le traitement des donn\xE9es personnelles conform\xE9ment aux hypoth\xE8ses pr\xE9vues par le RGPD ;</li><li>le droit de s\u2019opposer au traitement des donn\xE9es : les utilisateurs peuvent s\u2019opposer \xE0 ce que leurs donn\xE9es soient trait\xE9es conform\xE9ment aux hypoth\xE8ses pr\xE9vues par le RGPD ;</li><li>le droit \xE0 la portabilit\xE9 : ils peuvent r\xE9clamer que la Plateforme leur remette les donn\xE9es personnelles qu'ils ont fournies pour les transmettre \xE0 une nouvelle Plateforme.</li></ul><p><br></p><p>Vous pouvez exercer ce droit en nous contactant, \xE0 l\u2019adresse suivante :<br>\xC9cole militaire des aspirants de Co\xEBtquidan, Acad\xE9mie militaire de Saint-Cyr Co\xEBtquidan, 56381 GUER Cedex, France.<br><br>Ou par email, \xE0 l\u2019adresse :<br><strong>emac.amscc@gmail.com</strong><br> <br>Toute demande doit \xEAtre accompagn\xE9e de la photocopie d\u2019un titre d\u2019identit\xE9 en cours de validit\xE9 sign\xE9 et faire mention de l\u2019adresse \xE0 laquelle l'\xE9diteur pourra contacter le demandeur. La r\xE9ponse sera adress\xE9e dans le mois suivant la r\xE9ception de la demande. Ce d\xE9lai d'un mois peut \xEAtre prolong\xE9 de deux mois si la complexit\xE9 de la demande et/ou le nombre de demandes l'exigent.<br><br>De plus, et depuis la loi n\xB02016-1321 du 7 octobre 2016, les personnes qui le souhaitent, ont la possibilit\xE9 d\u2019organiser le sort de leurs donn\xE9es apr\xE8s leur d\xE9c\xE8s. Pour plus d\u2019information sur le sujet, vous pouvez consulter le site Internet de la CNIL : <a href="https://www.cnil.fr/">https://www.cnil.fr/</a>.<br><br>Les utilisateurs peuvent aussi introduire une r\xE9clamation aupr\xE8s de la CNIL sur le site de la CNIL : <a href="https://www.cnil.fr/">https://www.cnil.fr</a>.&nbsp;<br><br>Nous vous recommandons de nous contacter dans un premier temps avant de d\xE9poser une r\xE9clamation aupr\xE8s de la CNIL, car nous sommes \xE0 votre enti\xE8re disposition pour r\xE9gler votre probl\xE8me.<br><br></p><h5>Article 9 - Utilisation des donn\xE9es</h5><p>Les donn\xE9es personnelles collect\xE9es aupr\xE8s des utilisateurs ont pour objectif la mise \xE0 disposition des services de la Plateforme, leur am\xE9lioration et le maintien d'un environnement s\xE9curis\xE9. La base l\xE9gale des traitements est&nbsp; l\u2019ex\xE9cution du contrat entre l\u2019utilisateur et la Plateforme. Plus pr\xE9cis\xE9ment, les utilisations sont les suivantes :<br><br></p><ul><li>acc\xE8s et utilisation de la Plateforme par l'utilisateur ;</li><li>gestion du fonctionnement et optimisation de la Plateforme ;</li><li>mise en \u0153uvre d'une assistance utilisateurs ;</li><li>v\xE9rification, identification et authentification des donn\xE9es transmises par l'utilisateur ;</li><li>personnalisation des services en affichant des publicit\xE9s en fonction de l'historique de navigation de l'utilisateur, selon ses pr\xE9f\xE9rences ;</li><li>pr\xE9vention et d\xE9tection des fraudes, malwares (malicious softwares ou logiciels malveillants) et gestion des incidents de s\xE9curit\xE9 ;</li><li>gestion des \xE9ventuels litiges avec les utilisateurs ;</li><li>envoi d'informations commerciales et publicitaires, en fonction des pr\xE9f\xE9rences de l'utilisateur ;</li></ul><p><br></p><h5>Article 10 - Politique de conservation des donn\xE9es</h5><p>La Plateforme conserve vos donn\xE9es pour la dur\xE9e n\xE9cessaire pour vous fournir ses services ou son assistance.<br>Dans la mesure raisonnablement n\xE9cessaire ou requise pour satisfaire aux obligations l\xE9gales ou r\xE9glementaires, r\xE9gler des litiges, emp\xEAcher les fraudes et abus ou appliquer nos modalit\xE9s et conditions, nous pouvons \xE9galement conserver certaines de vos informations si n\xE9cessaire, m\xEAme apr\xE8s que vous ayez ferm\xE9 votre compte ou que nous n'ayons plus besoin pour vous fournir nos services.<br><br></p><h5>Article 11- Partage des donn\xE9es personnelles avec des tiers</h5><p>Les donn\xE9es personnelles peuvent \xEAtre partag\xE9es avec des soci\xE9t\xE9s tierces exclusivement dans l\u2019Union europ\xE9enne, dans les cas suivants :</p><ul><li>lorsque l'utilisateur publie, dans les zones de commentaires libres de la Plateforme, des informations accessibles au public ;</li><li>quand l'utilisateur autorise le site web d'un tiers \xE0 acc\xE9der \xE0 ses donn\xE9es ;</li><li>quand la Plateforme recourt aux services de prestataires pour fournir l'assistance utilisateurs, la publicit\xE9 et les services de paiement. Ces prestataires disposent d'un acc\xE8s limit\xE9 aux donn\xE9es de l'utilisateur, dans le cadre de l'ex\xE9cution de ces prestations, et ont l'obligation contractuelle de les utiliser en conformit\xE9 avec les dispositions de la r\xE9glementation applicable en mati\xE8re protection des donn\xE9es \xE0 caract\xE8re personnel ;</li><li>si la loi l'exige, la Plateforme peut effectuer la transmission de donn\xE9es pour donner suite aux r\xE9clamations pr\xE9sent\xE9es contre la Plateforme et se conformer aux proc\xE9dures administratives et judiciaires.</li></ul><p><br></p><h5>Article 12 - Offres commerciales</h5><p>Vous \xEAtes susceptible de recevoir des offres commerciales de l'\xE9diteur. Si vous ne le souhaitez pas, veuillez cliquer sur le lien suivant :<br><strong>emac.amscc@gmail.com</strong>.<br>Si, lors de la consultation du site, vous acc\xE9dez \xE0 des donn\xE9es \xE0 caract\xE8re personnel, vous devez vous abstenir de toute collecte, de toute utilisation non autoris\xE9e et de tout acte pouvant constituer une atteinte \xE0 la vie priv\xE9e ou \xE0 la r\xE9putation des personnes. L'\xE9diteur d\xE9cline toute responsabilit\xE9 \xE0 cet \xE9gard.<br>Les donn\xE9es sont conserv\xE9es et utilis\xE9es pour une dur\xE9e conforme \xE0 la l\xE9gislation en vigueur.<br><br></p><h5>Article 13 - Cookies</h5><p>Qu\u2019est-ce qu\u2019un \xAB cookie \xBB ?<br>Un \xAB Cookie \xBB ou traceur est un fichier \xE9lectronique d\xE9pos\xE9 sur un terminal (ordinateur, tablette, smartphone,\u2026) et lu par exemple lors de la consultation d'un site internet, de la lecture d'un courrier \xE9lectronique, de l'installation ou de l'utilisation d'un logiciel ou d'une application mobile et ce, quel que soit le type de terminal utilis\xE9 (source : <a href="https://www.cnil.fr/fr/cookies-traceurs-que-dit-la-loi">https://www.cnil.fr/fr/cookies-traceurs-que-dit-la-loi</a>).<br>En naviguant sur ce site, des \xAB cookies \xBB \xE9manant de la soci\xE9t\xE9 responsable du site concern\xE9 et/ou des soci\xE9t\xE9s tiers pourront \xEAtre d\xE9pos\xE9s sur votre terminal.<br>Lors de la premi\xE8re navigation sur ce site, une banni\xE8re explicative sur l\u2019utilisation des \xAB cookies \xBB appara\xEEtra. D\xE8s lors, en poursuivant la navigation, le client et/ou prospect sera r\xE9put\xE9 inform\xE9 et avoir accept\xE9 l\u2019utilisation desdits \xAB cookies \xBB. Le consentement donn\xE9 sera valable pour une p\xE9riode de treize (13) mois. L'utilisateur a la possibilit\xE9 de d\xE9sactiver les cookies \xE0 partir des param\xE8tres de son navigateur.&nbsp;<br><br>Toutes les informations collect\xE9es ne seront utilis\xE9es que pour suivre le volume, le type et la configuration du trafic utilisant ce site, pour en d\xE9velopper la conception et l'agencement et \xE0 d'autres fins administratives et de planification et plus g\xE9n\xE9ralement pour am\xE9liorer le service que nous vous offrons.<br><br>Les cookies suivants sont pr\xE9sents sur ce site :&nbsp;<br><br></p><ul><li>cookie de loi permettant de ne plus afficher la banni\xE8re en bas de page. cookies de stockage local permettant de charger la page plus rapidement..</li></ul><p><br>La dur\xE9e de vie de ces cookies est de treize mois.<br><br>Pour plus d\u2019informations sur l\u2019utilisation, la gestion et la suppression des \xAB cookies \xBB, pour tout type de navigateur, nous vous invitons \xE0 consulter le lien suivant : <a href="https://www.cnil.fr/fr/cookies-les-outils-pour-les-maitriser">https://www.cnil.fr/fr/cookies-les-outils-pour-les-maitriser</a>.<br><br></p><h5>Article 14 - Photographies et repr\xE9sentation des produits</h5><p>Les photographies de produits, accompagnant leur description, ne sont pas contractuelles et n'engagent pas l'\xE9diteur.<br><br></p><h5>Article 15 - Loi applicable</h5><p>Les pr\xE9sentes conditions d'utilisation du site sont r\xE9gies par la loi fran\xE7aise et soumises \xE0 la comp\xE9tence des tribunaux du si\xE8ge social de l'\xE9diteur, sous r\xE9serve d'une attribution de comp\xE9tence sp\xE9cifique d\xE9coulant d'un texte de loi ou r\xE9glementaire particulier.<br><br></p><h5>Article 16 - Contactez-nous</h5><p>Pour toute question, information sur les produits pr\xE9sent\xE9s sur le site, ou concernant le site lui-m\xEAme, vous pouvez laisser un message \xE0 l'adresse suivante : <strong>emac.amscc@gmail.com</strong>.</p>`},page_not_found:{title:"Page non trouv\xE9e",description:"La page que vous essayez d'atteindre n'est pas disponible actuellement. Cela peut \xEAtre d\xFB au fait que la page n'existe pas ou a \xE9t\xE9 d\xE9plac\xE9e."},maintenance:{title:"Maintenance",description:"Maintenance en cours",back_soon:"Nous serons bient\xF4t de retour"},promotion:{list:{title:"Promotions",description:["Promotions de l'\xC9cole militaire des aspirants de Co\xEBtquidan.","Depuis sa fondation le <span>6 juillet 2021</span>, l'\xE9cole comptabilise {{numberOfPromotion}} promotions."],keywords:"",meta_description:""},detail:{title:"Promotions"},see_all:"Voir toutes",current:"Promotion actuelle",number:"Promotion n\xB0"},emac:{contact:{address:["\xC9cole militaire des aspirants de Co\xEBtquidan","Acad\xE9mie militaire de Saint-Cyr Co\xEBtquidan","56381 GUER Cedex","France"]}}}}}return e})();export{L as a,C as b,P as c,y as d,A as e,k as f,D as g};
